// api-client.ts
class MoneyWorksApiClient {
  constructor(private baseUrl: string) {}

  async getTaxRates(options?: {
    format?: string;
    filter?: string;
    limit?: number;
  }) {
    const params = new URLSearchParams();
    if (options?.format) params.set('format', options.format);
    if (options?.filter) params.set('filter', options.filter);
    if (options?.limit) params.set('limit', options.limit.toString());

    const response = await fetch(
      `${this.baseUrl}/api/v1/tables/TaxRate?${params}`
    );

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.error.message);
    }

    return response.json();
  }

  async evaluateScript(expression: string) {
    const response = await fetch(`${this.baseUrl}/api/v1/eval`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ expression })
    });

    return response.json();
  }

  async getCompanyInfo() {
    const response = await fetch(`${this.baseUrl}/api/v1/company`);
    return response.json();
  }
}

