// controllers/account.controller.ts
import { BaseTableController } from './base';
import { MoneyWorksAccount } from '@moneyworks/canonical';
import { AccountCode, YYYYMMDD } from '@moneyworks/utilities';

export class AccountController extends BaseTableController<MoneyWorksAccount> {
  getTableName(): string {
    return 'Account';
  }

  // Custom validation
  async validateRecord(record: any): Promise<void> {
    if (!record.AccountCode) {
      throw new Error('Account code is required');
    }

    // Validate account code format
    const codePattern = /^\d{1,2}-\d{4}$/;
    if (!codePattern.test(record.AccountCode)) {
      throw new Error('Invalid account code format');
    }
  }

  // Transform to branded types
  async transformRecord(record: any): Promise<MoneyWorksAccount> {
    return {
      ...record,
      AccountCode: record.AccountCode as AccountCode,
      DateCreated: record.DateCreated as YYYYMMDD,
      DateModified: record.DateModified as YYYYMMDD
    };
  }

  // Custom methods
  async getAccountsByType(type: string): Promise<MoneyWorksAccount[]> {
    return this.export({
      filter: `Type = '${type}'`,
      format: 'full'
    });
  }

  async getBalanceSheet(): Promise<MoneyWorksAccount[]> {
    return this.export({
      filter: 'Type IN ("Asset", "Liability", "Equity")',
      orderBy: 'Type, AccountCode',
      format: 'full'
    });
  }
}

