  };
});

// services/enhanced-cache.service.ts
import { CacheService } from './cache.service';
import { createHash } from 'crypto';

export class EnhancedCacheService extends CacheService {
  // Generate cache key from request params
  generateKey(prefix: string, params: any): string {
    const hash = createHash('md5')
      .update(JSON.stringify(params))
      .digest('hex');
    return `${prefix}:${hash}`;
  }

  // Cache with stale-while-revalidate
  async getOrFetch<T>(
    key: string,
    fetcher: () => Promise<T>,
    options: {
      ttl: number;
      staleTime?: number;
    }
  ): Promise<T> {
    const cached = await this.get<{
      data: T;
      timestamp: number;
    }>(key);

    const now = Date.now();

    // Return cached if fresh
    if (cached && (now - cached.timestamp) < options.ttl * 1000) {
      return cached.data;
    }

    // Return stale while revalidating
    if (cached && options.staleTime && 
        (now - cached.timestamp) < options.staleTime * 1000) {
      // Revalidate in background
      fetcher().then(data => {
        this.set(key, { data, timestamp: now }, { ttl: options.ttl });
      }).catch(console.error);

      return cached.data;
    }

    // Fetch fresh data
    const data = await fetcher();
    await this.set(key, { data, timestamp: now }, { ttl: options.ttl });
    return data;
  }
}

// Usage in route
app.get('/api/v1/tables/:table', async ({ params, query, cache }) => {
  const cacheKey = cache.generateKey(
    `table:${params.table}`,
    query
  );

  return cache.getOrFetch(
    cacheKey,
    () => controller.export(query),
    {
      ttl: 300,        // 5 minutes fresh
      staleTime: 3600  // 1 hour stale acceptable
    }
  );
});
